1092	///
1093	/// The borrow split (needing both `&mut LuaState` and `&mut dyn LuaFileHandle`)
1094	/// is resolved by collecting all formatted strings first and then writing them
1095	/// to the file handle obtained from the `LSTREAM_REGISTRY`.
1096	pub fn io_write(state: &mut LuaState) -> Result<usize, LuaError> {
