    static MODE_NAMES: &[&[u8]] = &[b"no", b"full", b"line"];

    let _ = tofile(state)?;
    let op = state.check_arg_option(2, None, MODE_NAMES)?;
    // C: lua_Integer sz = luaL_optinteger(L, 3, LUAL_BUFFERSIZE);
