fn funcname_from_call<'a>(
    state: &'a LuaState,
    ci: &CallInfo,
    name: &mut Option<Vec<u8>>,
) -> Option<&'static [u8]> {
    // C: if (ci->callstatus & CIST_HOOKED) { *name = "?"; return "hook"; }
    if ci.callstatus & CIST_HOOKED != 0 {
        *name = Some(b"?".to_vec());
